                    <Label htmlFor="ai-enabled" className="text-purple-600 dark:text-purple-400 font-medium">تفعيل الذكاء الصناعي</Label>
                  </div>
                  <ToggleSwitch
                    id="ai-enabled"
                    checked={formData.aiEnabled}
                    onCheckedChange={(checked) => setFormData({...formData, aiEnabled: checked})}
