                          </Button>
                        </CardContent>
                      </Card>
                      <div className="space-y-1 max-h-[150px] overflow-y-auto">
                        {filteredRules.length === 0 ? (
                          <div className="text-xs text-center py-3 text-muted-foreground">لا توجد قواعد</div>
