                          filteredRules.map((rule: any) => (
                            <Card key={rule.id} className={`border p-2 ${!rule.isActive ? 'opacity-50' : ''}`}>
                              <div className="flex items-center justify-between gap-2">
                                <div className="flex-1 min-w-0 max-w-sm">
                                  <p className="text-xs font-medium text-foreground truncate">{rule.name}</p>
                                  <p className="text-xs text-muted-foreground line-clamp-2 break-words">{rule.prompt}</p>
                                </div>
                                <div className="flex items-center gap-1">
                                  <ToggleSwitch checked={rule.isActive} onCheckedChange={() => toggleRuleMutation.mutate(rule.id)} size="sm" data-testid={`toggle-rule-${rule.id}`} />
                                  <Button size="icon" variant="ghost" className="h-5 w-5" onClick={() => { setSelectedRuleType('summarize'); handleEditRule(rule); }} data-testid={`button-edit-rule-${rule.id}`}>
                                    <Edit className="h-2 w-2" />
                                  </Button>
                                  <Button size="icon" variant="ghost" className="h-5 w-5 text-red-600" onClick={() => deleteRuleMutation.mutate(rule.id)} data-testid={`button-delete-rule-${rule.id}`}>
                                    <Trash2 className="h-2 w-2" />
                                  </Button>
                                </div>
                              </div>
                            </Card>
                          ))
                        )}
                      </div>
                    </div>

                    <div className="border-t pt-4 mt-4">
                      <Card className="border-2 border-dashed border-primary/30 bg-gradient-to-br from-primary/5 to-transparent">
                        <CardHeader className="pb-2">
                          <CardTitle className="text-sm flex items-center gap-2">
                            <Layers className="h-4 w-4 text-primary" />
                            القواعد المتقدمة للذكاء الاصطناعي
                          </CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-3">
                          <p className="text-xs text-muted-foreground">
                            إدارة قواعد متقدمة تشمل استبدال الكيانات، تعديل السياق، فلترة المحتوى، وقوالب النشر
                          </p>
                          <div className="grid grid-cols-2 gap-2">
                            <div className="flex items-center gap-2 text-xs bg-muted/50 p-2 rounded">
                              <Replace className="h-3 w-3 text-blue-500" />
                              <span>استبدال الكيانات</span>
                            </div>
                            <div className="flex items-center gap-2 text-xs bg-muted/50 p-2 rounded">
                              <Settings2 className="h-3 w-3 text-green-500" />
                              <span>قواعد السياق</span>
                            </div>
                            <div className="flex items-center gap-2 text-xs bg-muted/50 p-2 rounded">
                              <Filter className="h-3 w-3 text-orange-500" />
                              <span>فلاتر المحتوى</span>
                            </div>
                            <div className="flex items-center gap-2 text-xs bg-muted/50 p-2 rounded">
                              <FileText className="h-3 w-3 text-purple-500" />
                              <span>قوالب النشر</span>
                            </div>
