                          <Link href="/ai-rules">
                            <Button variant="outline" size="sm" className="w-full mt-2 gap-2">
                              <ExternalLink className="h-3 w-3" />
                              فتح صفحة القواعد المتقدمة
                            </Button>
                          </Link>
                        </CardContent>
                      </Card>
                    </div>
                  </>
