/**
 * API Client for Backend Communication
 * Provides typed methods for all API endpoints
 */

const API_BASE = "/api";

interface ApiError {
  error: string;
  details?: unknown;
}

class ApiClient {
  private async request<T>(
    endpoint: string,
    options?: RequestInit
  ): Promise<T> {
    const response = await fetch(`${API_BASE}${endpoint}`, {
      headers: {
        "Content-Type": "application/json",
        ...options?.headers,
      },
      ...options,
    });

    if (!response.ok) {
      const error: ApiError = await response.json();
      throw new Error(error.error || "API request failed");
    }

    return response.json();
  }

  // Authentication
  async login(username: string, password: string) {
    return this.request<{ user: any; message: string }>("/auth/login", {
      method: "POST",
      body: JSON.stringify({ username, password }),
    });
  }

  async register(username: string, password: string) {
    return this.request<{ user: any; message: string }>("/auth/register", {
      method: "POST",
      body: JSON.stringify({ username, password }),
    });
  }

  // Dashboard
  async getDashboardStats() {
    return this.request<{
      totalTasks: number;
      activeTasks: number;
      inactiveTasks: number;
      totalChannels: number;
      totalForwarded: number;
      aiEnabledTasks: number;
      videoEnabledTasks: number;
    }>("/dashboard/stats");
  }

  // Tasks
  async getTasks() {
    return this.request<any[]>("/tasks");
  }

  async getTask(id: number) {
    return this.request<any>(`/tasks/${id}`);
  }

  async createTask(data: any) {
    return this.request<any>("/tasks", {
      method: "POST",
      body: JSON.stringify(data),
    });
  }

  async updateTask(id: number, data: any) {
    return this.request<any>(`/tasks/${id}`, {
      method: "PATCH",
      body: JSON.stringify(data),
    });
  }

  async toggleTask(id: number) {
    return this.request<any>(`/tasks/${id}/toggle`, {
      method: "POST",
    });
  }

  async deleteTask(id: number) {
    return this.request<{ message: string }>(`/tasks/${id}`, {
      method: "DELETE",
    });
  }

  async getTaskStats(id: number, days: number = 7) {
    return this.request<any[]>(`/tasks/${id}/stats?days=${days}`);
