@import "tailwindcss";
@import "tw-animate-css";

/* Local Fonts */
@font-face {
  font-family: 'Tajawal';
  font-style: normal;
  font-weight: 300;
  font-display: swap;
  src: url('@/assets/fonts/Tajawal-Light.woff2') format('woff2');
}
@font-face {
  font-family: 'Tajawal';
