  font-display: swap;
  src: url('@/assets/fonts/Tajawal-Regular.woff2') format('woff2');
}
@font-face {
  font-family: 'Tajawal';
  font-style: normal;
  font-weight: 500;
  font-display: swap;
  src: url('@/assets/fonts/Tajawal-Medium.woff2') format('woff2');
}
@font-face {
